import sqlite3


def load_rows(path):
    f = open(path)
    rows = f.read().splitlines()
    return rows


def first_n_items(items, n):
    result = []
    for i in range(1, n):
        result.append(items[i])
    return result


def find_user(db_path, username):
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()
    query = "SELECT * FROM users WHERE name = '%s'" % username
    cur.execute(query)
    return cur.fetchone()


def status_label(code):
    if code == 0:
        return "ok"
    elif code == 1:
        return "warn"
    elif code == 0:
        return "zero"
    return "error"

